function openProject(id) {
  console.log('DEBUG: openProject started for id:', id);

  const project = DB.get(id);

  if (!project) {
    console.log('DEBUG: openProject project not found in DB');
    return;
  }

  state.currentProjectId = id;

  // Hủy active view 1 (dashboard), active view 2 (workspace)
  document.getElementById('view-projects')?.classList.remove('active');
  document.getElementById('view-workspace')?.classList.add('active');

  // Active bottom nav tab tương ứng (tab bốc KL)
  document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
  document.querySelector('.bottom-nav .nav-tab[data-tab="estimate"]')?.classList.add('active');

  document.getElementById('empty-state').style.display = 'none';

  const ws = document.getElementById('project-workspace');

  ws.style.display = 'block';

  ws.classList.add('visible');

  // Điền thông tin

  document.getElementById('ws-project-name').textContent = project.name;

  document.getElementById('ws-project-client').textContent  = project.client  ? `👤 ${project.client}`  : '';

  document.getElementById('ws-project-address').textContent = project.address ? `📍 ${project.address}` : '';

  document.getElementById('ws-project-date').textContent    = project.date    ? `📅 ${project.date}`    : '';

  console.log('DEBUG: openProject calling renderProjectList');
  renderProjectList();

  console.log('DEBUG: openProject calling refreshWorkspace');
  refreshWorkspace();
  console.log('DEBUG: openProject finished');

}

function refreshWorkspace() {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  renderStats(project);

  renderRooms(project);

  renderBOQ(project);

}

