function updateOtherCost(key, field, rawVal) {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  const oc = project.otherCosts ? { ...project.otherCosts } : {};

  if (!oc[key]) oc[key] = {};

  if (field === 'price' || field === 'qty') {

    oc[key][field] = parseFloat(rawVal) || 0;

  } else {

    oc[key][field] = rawVal;

  }

  DB.update(state.currentProjectId, { otherCosts: oc });

  // Cập nhật ô thành tiền của dòng này mà không re-render toàn bộ

  const saved = oc[key];

  const project2 = DB.get(state.currentProjectId);

  const totalFloor = (project2.rooms || []).reduce((s, r) => {

    const d = (+r.D||0)/1000, rv = (+r.R||0)/1000;

    return s + d * rv;

  }, 0);

  const OC_TEMPLATE = [

    { key: 'transport', autoQty: false, defaultQty: 1 },

    { key: 'debris',    autoQty: true },

    { key: 'scaffold',  autoQty: true },

    { key: 'design',    autoQty: true },

    { key: 'supervision', autoQty: false, defaultQty: 1 },

  ];

  const tmpl = OC_TEMPLATE.find(t => t.key === key);

  const qty  = tmpl?.autoQty ? totalFloor : +(saved.qty != null ? saved.qty : tmpl?.defaultQty || 1);

  const price = +saved.price || 0;

  const total = qty * price;

  // Cập nhật ô thành tiền dòng này

  const totalCell = document.getElementById(`oc-total-${key}`);

  if (totalCell) totalCell.textContent = total ? fmt(total, 0) : '';

  // === FIX #10: Tính lại Grand Total và cập nhật các dòng tổng ở cuối bảng ===

  const p3 = DB.get(state.currentProjectId);

  const vatRate3 = +(p3.vatRate ?? 8) / 100;

  // Tổng hạng mục phòng

  const grandSub = (p3.rooms || []).reduce((s, room) => {

    const calc = CALC.room(room);

    return s + calc.items.reduce((rs, it) => rs + (+it.total || 0), 0);

  }, 0);

  // Tổng chi phí khác

  const oc3 = p3.otherCosts || {};

  const tf3 = (p3.rooms||[]).reduce((s,r)=>s+(+r.D||0)/1000*(+r.R||0)/1000, 0);

  const ocSub = OC_TEMPLATE.reduce((s, tmpl3) => {

    const sv3 = oc3[tmpl3.key] || {};

    const q3  = tmpl3.autoQty ? tf3 : +(sv3.qty != null ? sv3.qty : tmpl3.defaultQty || 0);

    return s + q3 * (+(sv3.price || 0));

  }, 0);

  const totalBefore = grandSub + ocSub;

  const vatAmt3 = Math.round(totalBefore * vatRate3);

  const grandTotal3 = totalBefore + vatAmt3;

  // Cập nhật các dòng tổng (nếu chúng đang hiện trên màn hình)

  const subRow = document.getElementById('boq-row-subtotal');

  const vatRow = document.getElementById('boq-row-vat');

  const gtRow  = document.getElementById('boq-row-grandtotal');

  const wdRow  = document.getElementById('boq-row-words');

  const colSpanLeft = 7;

  if (subRow) subRow.innerHTML = `

    <td colspan="${colSpanLeft}" style="text-align:right;font-weight:700;padding:10px 12px;border-top:2px solid var(--border-color);color:var(--text-secondary);">Thành tiền (trước VAT):</td>

    <td style="text-align:right;font-weight:700;padding:10px 12px;border-top:2px solid var(--border-color);color:var(--brand-gold);" colspan="3">${fmt(totalBefore, 0)} đ</td>`;

  if (vatRow) vatRow.innerHTML = `

    <td colspan="${colSpanLeft}" style="text-align:right;padding:6px 12px;color:var(--text-secondary);">VAT (${Math.round(vatRate3*100)}%):</td>

    <td style="text-align:right;padding:6px 12px;color:var(--text-secondary);" colspan="3">${fmt(vatAmt3, 0)} đ</td>`;

  if (gtRow) gtRow.innerHTML = `

    <td colspan="8" style="text-align:center;font-weight:800;padding:10px 12px;font-size:14px;border-top:2px solid var(--brand-gold);color:var(--text-main);">TỔNG CỘNG</td>

    <td style="text-align:right;font-weight:800;padding:10px 12px;font-size:14px;border-top:2px solid var(--brand-gold);color:var(--brand-gold);" colspan="2">${fmt(grandTotal3, 0)} đ</td>`;

  if (wdRow) wdRow.innerHTML = `

    <td colspan="10" style="padding:8px 12px;font-style:italic;color:var(--text-secondary);font-size:12px;border-top:1px dashed var(--border-color);">Bằng chữ: <strong style="color:var(--text-main);">${numberToWords(grandTotal3)}</strong></td>`;

}

// =============================================

// HẠNG MỤC THỦ CÔNG — Thêm / Xóa

// (Các hàm openAddItemDialog/saveAddItem/closeAddItem đã được

//  định nghĩa ở trên — dùng inline row editing)

// =============================================

function moveBoqRow(roomId, key, dir) {

  const project = DB.get(state.currentProjectId);

  const room = (project?.rooms||[]).find(r => r.id === roomId);

  if (!room) return;

  // Lay thu tu hien tai tu CALC

  const calc = CALC.room(room);

  const keys = calc.items.map(it => it._key);

  const idx  = keys.indexOf(key);

  if (idx < 0) return;

  const newIdx = idx + dir;

  if (newIdx < 0 || newIdx >= keys.length) return;

  // Swap

  [keys[idx], keys[newIdx]] = [keys[newIdx], keys[idx]];

  // Neu swap 2 custom items -> update customItems order

  const aKey = calc.items[idx]._key;

  const bKey = calc.items[newIdx]._key;

  const updates = { rowOrder: keys };

  if (aKey.startsWith('ci:') && bKey.startsWith('ci:')) {

    const ci = [...(room.customItems||[])];

    const aId = aKey.slice(3), bId = bKey.slice(3);

    const ai = ci.findIndex(c=>c.id===aId), bi = ci.findIndex(c=>c.id===bId);

    if (ai>=0 && bi>=0) { [ci[ai],ci[bi]] = [ci[bi],ci[ai]]; updates.customItems = ci; }

  }

  DB.updateRoom(state.currentProjectId, roomId, updates);

  refreshWorkspace();

}

function moveCustomItem(roomId, itemId, dir) {

  const project = DB.get(state.currentProjectId);

  const room = (project?.rooms || []).find(r => r.id === roomId);

  if (!room) return;

  const ci = [...(room.customItems || [])];

  const idx = ci.findIndex(c => c.id === itemId);

  const newIdx = idx + dir;

  if (newIdx < 0 || newIdx >= ci.length) return;

  [ci[idx], ci[newIdx]] = [ci[newIdx], ci[idx]];

  DB.updateRoom(state.currentProjectId, roomId, { customItems: ci });

  refreshWorkspace();

}

function removeCustomItem(roomId, itemId) {

  if (!confirm('Xóa hạng mục này?')) return;

  const project = DB.get(state.currentProjectId);

  const room = (project?.rooms || []).find(r => r.id === roomId);

  if (!room) return;

  DB.updateRoom(state.currentProjectId, roomId, {

    customItems: (room.customItems || []).filter(ci => ci.id !== itemId)

  });

  refreshWorkspace();

}

