function openProjectModal(project = null) {

  const isEdit = !!project;

  document.getElementById('modal-project-title').textContent = isEdit ? 'Sửa Dự Án' : 'Tạo Dự Án Mới';

  document.getElementById('proj-name').value         = project?.name        || '';

  document.getElementById('proj-client').value       = project?.client      || '';

  document.getElementById('proj-address').value      = project?.address     || '';

  document.getElementById('proj-date').value         = project?.date        || today();

  document.getElementById('proj-vat-rate').value     = project?.vatRate     ?? 8;

  let defaultSender = '';
  let defaultCompany = '';
  let defaultCompanyAddr = '';
  if (!isEdit) {
    try {
      const saved = JSON.parse(localStorage.getItem('bluedecor_default_sender_info') || '{}');
      defaultSender = saved.sender || '';
      defaultCompany = saved.company || '';
      defaultCompanyAddr = saved.companyAddr || '';
    } catch (e) {}
  }

  document.getElementById('proj-sender').value       = project?.sender      || defaultSender;

  const subtitleEl = document.getElementById('proj-subtitle');
  if (subtitleEl) subtitleEl.value = project?.subtitle || '';

  document.getElementById('proj-company').value      = project?.company     || defaultCompany;

  document.getElementById('proj-company-addr').value = project?.companyAddr || defaultCompanyAddr;

  document.getElementById('proj-recipient').value    = project?.recipient   || '';

  document.getElementById('proj-client-co').value    = project?.clientCo    || '';

  document.getElementById('proj-client-addr').value  = project?.clientAddr  || '';

  const type = project?.type || 'residential';
  const stars = project?.stars || '1-2';
  const nature = project?.nature || 'new';

  document.getElementById('proj-type').value = type;
  document.getElementById('proj-stars').value = stars;
  
  const radios = document.getElementsByName('proj-nature');
  for (const r of radios) {
    r.checked = (r.value === nature);
  }

  const projStarsGroup = document.getElementById('proj-stars-group');
  const projStarsWarning = document.getElementById('proj-stars-warning');
  if (type === 'hotel' || type === 'resort') {
    projStarsGroup.style.display = 'block';
    if (stars === '4-5') {
      projStarsWarning.style.display = 'block';
    } else {
      projStarsWarning.style.display = 'none';
    }
  } else {
    projStarsGroup.style.display = 'none';
    projStarsWarning.style.display = 'none';
  }

  document.getElementById('modal-project').classList.add('open');

  setTimeout(() => document.getElementById('proj-name').focus(), 50);

}

function closeProjectModal() {

  document.getElementById('modal-project').classList.remove('open');

}

function saveProject() {
  console.log('DEBUG: saveProject started');

  const name = document.getElementById('proj-name').value.trim();

  if (!name) {

    document.getElementById('proj-name').focus();

    document.getElementById('proj-name').style.borderColor = 'var(--brand-red)';

    return;

  }

  document.getElementById('proj-name').style.borderColor = '';

  const data = {

    name,

    client:      document.getElementById('proj-client').value.trim(),

    address:     document.getElementById('proj-address').value.trim(),

    date:        document.getElementById('proj-date').value,

    vatRate:     parseFloat(document.getElementById('proj-vat-rate').value) || 0,

    sender:      document.getElementById('proj-sender').value.trim(),

    subtitle:    document.getElementById('proj-subtitle') ? document.getElementById('proj-subtitle').value.trim() : '',

    company:     document.getElementById('proj-company').value.trim(),

    companyAddr: document.getElementById('proj-company-addr').value.trim(),

    recipient:   document.getElementById('proj-recipient').value.trim(),

    clientCo:    document.getElementById('proj-client-co').value.trim(),

    clientAddr:  document.getElementById('proj-client-addr').value.trim(),

    type:        document.getElementById('proj-type').value,

    stars:       (document.getElementById('proj-type').value === 'hotel' || document.getElementById('proj-type').value === 'resort') ? document.getElementById('proj-stars').value : null,

    nature:      document.querySelector('input[name="proj-nature"]:checked')?.value || 'new',

  };

  console.log('DEBUG: saveProject data gathered:', data);

  const isEdit = document.getElementById('modal-project-title').textContent === 'Sửa Dự Án';

  if (isEdit && state.currentProjectId) {
    console.log('DEBUG: saveProject isEdit: true, updating project');

    DB.update(state.currentProjectId, data);

    // Cập nhật header

    document.getElementById('ws-project-name').textContent    = data.name;

    document.getElementById('ws-project-client').textContent  = data.client  ? `👤 ${data.client}`  : '';

    document.getElementById('ws-project-address').textContent = data.address ? `📍 ${data.address}` : '';

    document.getElementById('ws-project-date').textContent    = data.date    ? `📅 ${data.date}`    : '';

  } else {
    console.log('DEBUG: saveProject isEdit: false, creating project');

    const project = DB.create(data);
    console.log('DEBUG: DB.create returned project:', project);

    openProject(project.id);
    console.log('DEBUG: openProject finished');

  }

  console.log('DEBUG: saveProject closing modal');
  closeProjectModal();

  console.log('DEBUG: saveProject rendering project list');
  renderProjectList();

  console.log('DEBUG: saveProject rendering dashboard projects');
  renderDashboardProjects();
  console.log('DEBUG: saveProject fully finished');

}

function deleteCurrentProject() {
  const project = DB.get(state.currentProjectId);
  if (!project) return;

  if (!confirm(`Xóa dự án "${project.name}"?\n\nHành động này không thể hoàn tác.`)) return;

  // Xóa toàn bộ ảnh dự án khỏi IndexedDB
  if (project.sitePhotos) {
    project.sitePhotos.forEach(p => {
      if (p.id) PhotoDB.deletePhoto(p.id).catch(err => console.error('Failed to delete site photo:', p.id, err));
    });
  }
  if (project.rooms) {
    const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
    project.rooms.forEach(room => {
      if (room.photos) {
        categories.forEach(cat => {
          const list = room.photos[cat] || [];
          list.forEach(p => {
            if (p.id) PhotoDB.deletePhoto(p.id).catch(err => console.error('Failed to delete project room photo:', p.id, err));
          });
        });
      }
    });
  }

  DB.remove(state.currentProjectId);
  state.currentProjectId = null;
  document.getElementById('project-workspace').style.display = 'none';
  document.getElementById('project-workspace').classList.remove('visible');
  document.getElementById('view-workspace')?.classList.remove('active');
  document.getElementById('view-projects')?.classList.add('active');

  // Update bottom nav
  document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
  document.querySelector('.bottom-nav .nav-tab[data-tab="projects"]')?.classList.add('active');

  renderProjectList();

  renderDashboardProjects();

}

