function renderQuickRoomButtons(projType) {
  const container = document.getElementById('room-quick-btns');
  if (!container) return;
  const rooms = QUICK_ROOMS_BY_PROJECT_TYPE[projType] || QUICK_ROOMS_BY_PROJECT_TYPE.residential;
  container.innerHTML = rooms.map(r => `
    <button type="button" class="quick-btn" data-name="${r.name}">${r.label}</button>
  `).join('');
}

function autoDetectRoomFunction(name) {
  if (!name) return 'kho';
  const norm = name.toLowerCase();
  if (norm.includes('mổ') || norm.includes('ivf') || norm.includes('vô trùng') || norm.includes('sạch') || norm.includes('lab') || norm.includes('cách ly')) {
    return 'sach';
  }
  if (norm.includes('wc') || norm.includes('tắm') || norm.includes('giặt') || norm.includes('ướt') || norm.includes('bể bơi') || norm.includes('hồ bơi') || norm.includes('gội') || norm.includes('xông hơi') || norm.includes('pantry') || norm.includes('bếp')) {
    return 'uot';
  }
  if (norm.includes('x-quang') || norm.includes('ct-scan') || norm.includes('phóng xạ') || norm.includes('bức xạ') || norm.includes('chụp')) {
    return 'buc-xa';
  }
  if (norm.includes('họp vip') || norm.includes('tiêu âm') || norm.includes('massage') || norm.includes('karaoke')) {
    return 'tieu-am';
  }
  return 'kho';
}

function updateRoomDiagnostic(val) {

  const diagnosticHint = document.getElementById('room-diagnostic-hint');

  if (!diagnosticHint) return;

  const messages = {

    kho: '',

    uot: '⚠️ <strong>Cảnh báo Khu vực ẩm ướt:</strong> Yêu cầu hệ thống ngầm kiểm tra rủi ro thấm ngược. Hãy kiểm tra kỹ cổ ống xuyên sàn, thực hiện chống thấm ngược và quét chống thấm kỹ vách chân tường lên cao tối thiểu 30cm (150cm đối với khu vực sen vòi).',

    sach: '⚠️ <strong>Yêu cầu Phòng sạch / Vô trùng:</strong> Yêu cầu ngầm kiểm tra độ phẳng sàn tuyệt đối để đi vinyl kháng khuẩn liền mạch, cao độ trần cho HVAC áp lực dương. Đảm bảo độ phẳng sàn tuyệt đối (sai số &lt; 2mm).',

    'buc-xa': '⚠️ <strong>Yêu cầu Phòng bức xạ / Chẩn đoán hình ảnh:</strong> Yêu cầu bọc chì chống phóng xạ cho vách và hệ cửa. Vách và hệ thống cửa phải được bọc tấm chì chống phóng xạ dày tiêu chuẩn, sơn cản xạ và kiểm định an toàn.',

    'tieu-am': '⚠️ <strong>Yêu cầu Khu vực tiêu âm:</strong> Yêu cầu đặc thù âm thanh. Sử dụng vách thạch cao tiêu âm, tấm tiêu âm sợi ép hoặc gỗ đục lỗ tiêu âm để đảm bảo tiêu âm (RT60) đạt chuẩn kỹ thuật.'

  };

  const msg = messages[val];

  if (msg) {

    diagnosticHint.innerHTML = msg;

    diagnosticHint.style.display = 'block';

  } else {

    diagnosticHint.style.display = 'none';

    diagnosticHint.innerHTML = '';

  }

}

function closeRoomModal(forceClose = false) {
  if (!forceClose && isRoomFormDirty()) {
    if (!confirm('Bạn có thay đổi chưa lưu trong phòng này. Bạn có chắc chắn muốn hủy bỏ?')) {
      return;
    }
  }

  document.getElementById('modal-room').classList.remove('open');

  if (state.categoryObjectUrls) {
    Object.keys(state.categoryObjectUrls).forEach(cat => {
      state.categoryObjectUrls[cat].forEach(url => URL.revokeObjectURL(url));
    });
    state.categoryObjectUrls = null;
  }

  state.editingRoomId = null;
  state.originalRoomData = null;
}

function saveRoom() {
  const name = document.getElementById('room-name').value.trim();
  if (!name) {
    showToast('Vui lòng nhập tên phòng!', 'warning');
    document.getElementById('room-name').focus();
    document.getElementById('room-name').style.borderColor = 'var(--brand-red)';
    return;
  }
  const D = parseFloat(document.getElementById('room-D').value);
  const R = parseFloat(document.getElementById('room-R').value);
  if (!D || !R) {
    showToast('Vui lòng nhập kích thước Dài (D) và Rộng (R)!', 'warning');
    if (!D) document.getElementById('room-D').focus();
    else document.getElementById('room-R').focus();
    return;
  }

  document.getElementById('room-name').style.borderColor = '';
  
  // Dọn dẹp ảnh cũ bị xóa khỏi danh sách
  const oldRoom = state.editingRoomId ? DB.get(state.currentProjectId)?.rooms.find(r => r.id === state.editingRoomId) : null;
  const oldPhotoIds = [];
  if (oldRoom && oldRoom.photos) {
    const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
    categories.forEach(cat => {
      const list = oldRoom.photos[cat] || [];
      list.forEach(p => { if (p.id) oldPhotoIds.push(p.id); });
    });
  }

  const roomData = getRoomDataFromUI();
  
  const newPhotoIds = [];
  const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
  categories.forEach(cat => {
    const list = roomData.photos[cat] || [];
    list.forEach(p => { if (p.id) newPhotoIds.push(p.id); });
  });

  const deletedPhotoIds = oldPhotoIds.filter(id => !newPhotoIds.includes(id));
  deletedPhotoIds.forEach(id => {
    PhotoDB.deletePhoto(id).catch(err => console.error('Failed to delete orphaned photo:', id, err));
  });

  try {
    if (state.editingRoomId) {
      DB.updateRoom(state.currentProjectId, state.editingRoomId, roomData);
      showToast('Đã cập nhật thông tin phòng!', 'success');
    } else {
      DB.addRoom(state.currentProjectId, roomData);
      showToast('Đã thêm phòng mới thành công!', 'success');
    }
    closeRoomModal(true);
    refreshWorkspace();
    renderProjectList();
  } catch (e) {
    if (e.name === 'QuotaExceededError') {
      showToast('Bộ nhớ đầy! Vui lòng xóa bớt ảnh hoặc dữ liệu cũ rồi thử lại.', 'error');
      console.error('QuotaExceededError — localStorage đầy:', e);
    } else {
      showToast('Lỗi khi lưu phòng. Vui lòng thử lại.', 'error');
      console.error('saveRoom error:', e);
    }
  }
}

function editRoom(roomId) {

  const project = DB.get(state.currentProjectId);

  const room = project?.rooms.find(r => r.id === roomId);

  if (room) openRoomModal(room);

}

function deleteRoom(roomId) {
  if (!confirm('Xóa phòng này?')) return;

  const project = DB.get(state.currentProjectId);
  const room = project?.rooms.find(r => r.id === roomId);
  if (room && room.photos) {
    const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
    categories.forEach(cat => {
      const list = room.photos[cat] || [];
      list.forEach(p => {
        if (p.id) PhotoDB.deletePhoto(p.id).catch(err => console.error('Failed to delete room photo:', p.id, err));
      });
    });
  }

  DB.removeRoom(state.currentProjectId, roomId);
  refreshWorkspace();
  renderProjectList();
}

