// Trạng thái tab preview

let _pvTab = 'summary';

function switchPreviewTab(tab) {

  _pvTab = tab;

  const isSummary = tab === 'summary';

  // Cập nhật style tab button

  document.getElementById('pv-tab-summary').style.background = isSummary ? 'var(--brand-gold)' : 'var(--bg-elevated)';

  document.getElementById('pv-tab-summary').style.color      = isSummary ? '#000' : 'var(--text-secondary)';

  document.getElementById('pv-tab-detail').style.background  = !isSummary ? 'var(--brand-gold)' : 'var(--bg-elevated)';

  document.getElementById('pv-tab-detail').style.color       = !isSummary ? '#000' : 'var(--text-secondary)';

  // Hiện/ẩn panel

  document.getElementById('pv-panel-summary').style.display = isSummary ? '' : 'none';

  document.getElementById('pv-panel-detail').style.display  = !isSummary ? '' : 'none';

  // Hiện/ẩn dropdown phòng

  document.getElementById('pv-room-select').style.display = !isSummary ? '' : 'none';

  openPreview();

}

// Feature #12: In bảng từ Preview modal

function printPreview() {

  // Lấy nội dung panel đang hiện

  const activePanel = _pvTab === 'summary'

    ? document.getElementById('pv-panel-summary')

    : document.getElementById('pv-panel-detail');

  if (!activePanel) return;

  const project = DB.get(state.currentProjectId);

  const title    = document.getElementById('pv-doc-title')?.textContent || 'BẢNG DỰ TOÁN';

  const projName = project?.name || '';

  const company  = project?.company || '';

  const dateStr  = project?.date ? new Date(project.date).toLocaleDateString('vi-VN') : '';

  // Lấy CSS của trang hiện tại để dùng lại trong cửa sổ in

  const styles = Array.from(document.styleSheets).map(ss => {

    try { return Array.from(ss.cssRules).map(r => r.cssText).join('\n'); }

    catch { return ''; }

  }).join('\n');

  const w = window.open('', '_blank', 'width=900,height=700');

  w.document.write(`<!DOCTYPE html><html><head>

    <meta charset="UTF-8">

    <title>${title} — ${projName}</title>

    <style>

      ${styles}

      body { background:#fff !important; color:#111 !important; padding:20px; font-family:Arial,sans-serif; }

      .pv-head { margin-bottom:16px; }

      table { width:100%; border-collapse:collapse; font-size:12px; }

      th, td { border:1px solid #ccc; padding:5px 8px; }

      th { background:#1a1a2e; color:#fff; }

      .pv-room-hdr td {

        background:#fff !important;

        color:#000 !important;

        font-weight:800;

        border-top:1px solid #000 !important;

        border-bottom:1px solid #000 !important;

        border-left:none !important;

        border-right:none !important;

      }

      .pv-room-hdr td:first-child {

        border-left:1px solid #000 !important;

      }

      .pv-room-hdr td:last-child {

        border-right:1px solid #000 !important;

      }

      .pv-subtotal td { background:#f5f0e0; font-weight:700; }

      @media print { button { display:none !important; } body { padding:0; } }

    </style>

  </head><body>

    <div class="pv-head">

      <h2 style="margin:0 0 4px;font-size:16px;">${company}</h2>

      <h3 style="margin:0 0 8px;font-size:14px;">${title}</h3>

      <p style="margin:0;font-size:12px;color:#555;">${projName} ${dateStr ? '· Ngày: '+dateStr : ''}</p>

    </div>

    ${activePanel.querySelector('table')?.outerHTML || activePanel.innerHTML}

  </body></html>`);

  w.document.close();

  setTimeout(() => { w.focus(); w.print(); }, 400);

}

function openPreview() {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  // Điền thông tin project

  if (document.getElementById('pv-subtitle')) {

    document.getElementById('pv-subtitle').textContent = (project.subtitle || project.name || '').toUpperCase();

  }

  if (document.getElementById('pv-project-name')) {

    document.getElementById('pv-project-name').textContent = `CÔNG TRÌNH: ${project.client || ''}`.toUpperCase();

  }

  if (document.getElementById('pv-sender-name')) {

    document.getElementById('pv-sender-name').textContent = project.sender || '';

  }

  if (document.getElementById('pv-sender-company')) {

    document.getElementById('pv-sender-company').textContent = project.company || '';

  }

  if (document.getElementById('pv-sender-addr')) {

    document.getElementById('pv-sender-addr').textContent = project.companyAddr || '';

  }

  if (document.getElementById('pv-client-name')) {

    document.getElementById('pv-client-name').textContent = project.recipient || '';

  }

  if (document.getElementById('pv-client-company')) {

    document.getElementById('pv-client-company').textContent = project.clientCo || '';

  }

  if (document.getElementById('pv-client-addr')) {

    document.getElementById('pv-client-addr').textContent = project.clientAddr || project.address || '';

  }

  const allRooms = project.rooms || [];

  // Cập nhật dropdown phòng trong preview

  const pvRoomSel = document.getElementById('pv-room-select');

  if (pvRoomSel) {

    const prevPvRoom = pvRoomSel.value;

    pvRoomSel.innerHTML = '<option value="all">File tổng</option>' +

      allRooms.map(r => `<option value="${r.id}">${r.name}</option>`).join('');

    if (Array.from(pvRoomSel.options).some(o => o.value === prevPvRoom)) {

      pvRoomSel.value = prevPvRoom;

    }

  }

  // ── Tab Tổng Hợp ──────────────────────────────

  if (_pvTab === 'summary') {

    document.getElementById('pv-doc-title').textContent = 'BẢNG TỔNG HỢP KHỐI LƯỢNG';

    if (document.getElementById('pv-subtitle'))      document.getElementById('pv-subtitle').textContent      = (project.subtitle || project.name || '').toUpperCase();

    if (document.getElementById('pv-project-name')) document.getElementById('pv-project-name').textContent = `CÔNG TRÌNH: ${project.client || ''}`.toUpperCase();

    _renderPreviewSummary(project, allRooms);

  } else {

    // ── Tab Chi Tiết ──────────────────────────────

    const selRoomId = pvRoomSel ? pvRoomSel.value : 'all';

    const filteredRooms = selRoomId === 'all' ? allRooms : allRooms.filter(r => r.id === selRoomId);

    const titleRoom = selRoomId === 'all' ? '' : ` — ${(allRooms.find(r=>r.id===selRoomId)?.name||'').toUpperCase()}`;

    document.getElementById('pv-doc-title').textContent = selRoomId === 'all' ? 'BẢNG KHỐI LƯỢNG' : 'BẢNG KHỐI LƯỢNG - ' + (allRooms.find(r=>r.id===selRoomId)?.name||'').toUpperCase();

    if (document.getElementById('pv-subtitle'))      document.getElementById('pv-subtitle').textContent      = (project.subtitle || project.name || '').toUpperCase();

    if (document.getElementById('pv-project-name')) document.getElementById('pv-project-name').textContent = `CÔNG TRÌNH: ${project.client || ''}`.toUpperCase();

    _renderPreviewDetail(project, filteredRooms, selRoomId === 'all');

  }

  document.getElementById('modal-preview').classList.add('open');

  reIcons();

}

// Render tab Tổng Hợp (có cột từng phòng)

function _renderPreviewSummary(project, rooms) {

  const summaryItems = CALC.projectSummary(project);

  // Rebuild thead động mỗi lần (tránh bug sau lần gọi thứ 2+)

  const sumTable = document.getElementById('pv-sum-table');

  if (sumTable) {

    const roomThCols = rooms.map(r =>

      `<th style="width:90px;text-align:right;font-size:11px;color:var(--brand-blue-light);">${r.name.length > 12 ? r.name.substring(0,12)+'…' : r.name}</th>`

    ).join('');

    sumTable.querySelector('thead').innerHTML = `<tr class="pv-head-row-1">

      <th style="width:36px;">STT</th>

      <th>HẠNG MỤC</th>

      <th style="width:48px;">Đ.VỊ</th>

      ${roomThCols}

      <th style="width:100px;">TỔNG SL</th>

      <th style="width:110px;">ĐƠN GIÁ (đ)</th>

      <th style="width:130px;">THÀNH TIỀN (đ)</th>

      <th style="width:150px;">GHI CHÚ</th>

    </tr>`;

  }

  let sumHtml = '';
  let grandTotal = 0;

  const groups = { construction: [], furniture: [], elec: [], sanitary: [] };

  summaryItems.forEach(item => {

    groups[categorizeSummaryItem(item)].push(item);

  });

  const catRomNums = ['I', 'II', 'III', 'IV', 'V', 'VI'];

  let catRomIdx = 0;

  const categoriesConfig = [
    { key: 'construction', rom: 'I',   label: 'XÂY DỰNG CƠ BẢN (bao gồm tất cả các hạng mục sàn tường trần)' },
    { key: 'elec',         rom: 'II',  label: 'THIẾT BỊ ĐIỆN' },
    { key: 'furniture',    rom: 'III', label: 'THIẾT BỊ NỘI THẤT' },
    { key: 'sanitary',     rom: 'IV',  label: 'NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM' }
  ];

  categoriesConfig.forEach(catConf => {

    const itemsInCat = groups[catConf.key];

    if (itemsInCat && itemsInCat.length > 0) {

      const rom = catConf.rom;

      sumHtml += `<tr class="pv-room-hdr"><td style="text-align:center;font-weight:700;">${rom}</td><td colspan="${rooms.length + 4}" style="font-weight:700;text-align:left;white-space:nowrap;">${catConf.label.toUpperCase()}</td><td></td><td></td></tr>`;


      let itemStt = 1;

      itemsInCat.forEach(item => {

        const roomQtyCells = rooms.map(r => {

          const calc = CALC.room(r);

          const match = calc.items.find(it => it.label === item.label && it.unit === item.unit);

          const q = match ? match.qty : 0;

          return `<td style="text-align:right;font-size:12px;padding:4px 8px;">${q > 0 ? fmt(q) : '—'}</td>`;

        }).join('');

        grandTotal += item.total || 0;

        sumHtml += `<tr class="pv-item">

          <td class="pv-stt">${itemStt++}</td>

          <td style="padding-left:15px !important;">${item.label}</td>

          <td class="pv-center">${item.unit}</td>

          ${roomQtyCells}

          <td class="pv-num" style="font-weight:700;color:var(--brand-blue-light);">${fmt(item.qty)}</td>

          <td class="pv-num">${item.price ? fmt(item.price, 0) : ''}</td>

          <td class="pv-num" style="font-weight:700;">${item.total ? fmt(item.total, 0) : ''}</td>

          <td class="pv-note">${item.note || ''}</td>

        </tr>`;

      });

    }

  });

  // Chi phí khác

  const totalFloor = rooms.reduce((s, r) => s + (+r.D||0)/1000 * (+r.R||0)/1000, 0);

  const OC_TEMPLATE = [

    { key:'transport',   label:'Phí vận chuyển',   unit:'gói', autoQty:false, defaultQty:1 },

    { key:'debris',      label:'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác', unit:'m²', autoQty:true },

    { key:'scaffold',    label:'Phí thuê giàn giáo', unit:'m²',  autoQty:true },

    { key:'design',      label:'Phí thiết kế',      unit:'m²',   autoQty:true },

    { key:'supervision', label:'Phí giám sát ngoại tỉnh', unit:'lần', autoQty:false, defaultQty:1 },

  ];

  const oc = project.otherCosts || {};

  let hasOc = false, ocStt = 1;

  OC_TEMPLATE.forEach(tmpl => {

    const saved = oc[tmpl.key] || {};

    const qty = tmpl.autoQty ? totalFloor : (saved.qty != null ? saved.qty : tmpl.defaultQty);

    const price = saved.price || 0;

    const total = qty * price;

    if (price > 0 || qty > 0) {

      if (!hasOc) {

        const rom = catRomNums[catRomIdx++];

        sumHtml += `<tr class="pv-room-hdr"><td style="text-align:center;font-weight:700;">${rom}</td><td colspan="${rooms.length + 4}" style="font-weight:700;text-align:left;white-space:nowrap;">CHI PHÍ KHÁC</td><td></td><td></td></tr>`;


        hasOc = true;

      }

      grandTotal += total;

      const roomQtyCells = rooms.map(r => {
        const tf = (+r.D || 0) / 1000 * (+r.R || 0) / 1000;
        const roomQty = tmpl.autoQty ? +(tf.toFixed(2)) : +(saved.qty != null ? saved.qty : tmpl.defaultQty);
        return `<td style="text-align:right;font-size:12px;padding:4px 8px;">${roomQty > 0 ? fmt(roomQty) : '—'}</td>`;
      }).join('');

      sumHtml += `<tr class="pv-item">

        <td class="pv-stt">${ocStt++}</td>

        <td>${tmpl.label}</td>

        <td class="pv-center">${tmpl.unit}</td>

        ${roomQtyCells}

        <td class="pv-num">${fmt(qty)}</td>

        <td class="pv-num">${price ? fmt(price, 0) : ''}</td>

        <td class="pv-num">${total ? fmt(total, 0) : ''}</td>

        <td class="pv-note">${saved.note || ''}</td>

      </tr>`;

    }

  });

  document.getElementById('pv-sum-tbody').innerHTML = sumHtml;

  document.getElementById('pv-grand-total-label').textContent = 'TỔNG CỘNG';

  document.getElementById('pv-grand-total-value').textContent =

    grandTotal > 0 ? fmt(grandTotal, 0) + ' đ' : '(Chưa nhập đơn giá)';

}

// Render tab Chi Tiết (lọc theo phòng)

function _renderPreviewDetail(project, filteredRooms, showOtherCosts = false) {

  const romanNums = ['I','II','III','IV','V','VI','VII','VIII','IX','X',

                     'XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX'];

  const allRooms = project.rooms || [];

  let html = '';

  let stt = 1;

  let grandTotal = 0;

  filteredRooms.forEach((room) => {

    const globalIdx = allRooms.indexOf(room);

    const calc  = CALC.room(room);

    const D = (+room.D || 0) / 1000;

    const R = (+room.R || 0) / 1000;

    const perimStr = (2*(D+R)).toFixed(2).replace('.',',');

    const roman = 'I';

    let roomTotal = 0;

    stt = 1; // reset STT mỗi phòng

    const renderItemHtml = (item) => {
      if (item.surface === 'custom') {
        const ci = (room.customItems||[]).find(c => c.id === item.itemId);
        if (ci) {
          const labelTrim = (ci.label||'').trim();
          const isSubHdr  = labelTrim.length > 1 && labelTrim === labelTrim.toUpperCase();
          if (isSubHdr) {
            stt = 1; // reset STT
            html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;"></td><td style="font-weight:700;text-align:left;">${ci.label}</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr>`;
            return;
          }
        }
      }

      if (item.surface === 'elecHeader') {
        return;
      }

      if (item.surface === 'noteHeader') {
        stt = 1;
        html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;"></td><td style="font-weight:700;text-align:left;">CHI TIẾT TỪ GHI CHÚ</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr>`;
        return;
      }

      const isManual = item.surface === 'elecManual';
      const rowClass = item.surface === 'perimeter' ? 'pv-perim' : 'pv-item';
      const qtyDisplay = isManual && item.qty === 0 ? '<em style="color:var(--brand-gold)">tự điền</em>' : (item.formula || fmt(item.qty));

      html += `<tr class="${rowClass}">
        <td class="pv-stt">${stt++}</td>
        <td style="${isManual ? 'color:var(--brand-gold);font-style:italic;' : ''} padding-left:15px !important;">${item.label}</td>
        <td class="pv-num">${item.dai  ? fmtMM(item.dai)  : ''}</td>
        <td class="pv-num">${item.rong ? fmtMM(item.rong) : ''}</td>
        <td class="pv-num">${item.cao  ? fmtMM(item.cao)  : ''}</td>
        <td class="pv-center">${item.unit}</td>
        <td class="pv-num" style="white-space:normal;font-size:10.5px;">${qtyDisplay}</td>
        <td class="pv-num">${item.price ? fmt(item.price, 0) : ''}</td>
        <td class="pv-num">${item.total ? fmt(item.total, 0) : ''}</td>
        <td class="pv-note">${(() => {
          let noteHtml = item.note || '';
          const catPhotos = getRoomPhotos(room, item.photoCategory);
          if (catPhotos.length > 0) {
            const photosMarkup = `<div class="pv-row-photos" style="display:flex; flex-wrap:wrap; gap:4px; margin-top:4px;">` +
              catPhotos.map(p => `
                <img src="${p.data}" style="width:120px; max-width:120px; height:auto; border-radius:4px; border:1px solid rgba(255,255,255,0.1); cursor:pointer;" onclick="window.viewPhotoData('${p.data.replace(/'/g, "\\'")}')" title="${p.name}">
              `).join('') + `</div>`;
            noteHtml = noteHtml ? `${noteHtml}<br>${photosMarkup}` : photosMarkup;
          }
          return noteHtml;
        })()}</td>
      </tr>`;

      roomTotal += item.total || 0;
      grandTotal += item.total || 0;
    };

    // I. XÂY DỰNG CƠ BẢN
    html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;">I</td><td colspan="7" style="font-weight:700;text-align:left;white-space:nowrap;">XÂY DỰNG CƠ BẢN — ${room.name.toUpperCase()}</td><td></td><td></td></tr>`;

    html += `<tr class="pv-room-info"><td colspan="10">
      📏 ${fmtMM(room.D)} × ${fmtMM(room.R)} × cao ${fmtMM(room.H)} mm
      &nbsp;|&nbsp; <strong>Chu vi: ${perimStr} m</strong>
      ${room.roomNote ? `&nbsp;|&nbsp; ${room.roomNote}` : ''}
    </td></tr>`;

    const constrItems = calc.items.filter(item => !['woodworkNote', 'plumbingNote', 'waterproofNote', 'elecHeader', 'elec', 'elecManual'].includes(item.surface));
    constrItems.forEach(item => {
      renderItemHtml(item);
    });

    // II. THIẾT BỊ ĐIỆN
    const elecItems = calc.items.filter(item => item.surface === 'elec' || item.surface === 'elecManual');
    if (elecItems.length > 0) {
      stt = 1;
      html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;">II</td><td colspan="7" style="font-weight:700;text-align:left;white-space:nowrap;">THIẾT BỊ ĐIỆN</td><td></td><td></td></tr>`;
      elecItems.forEach(item => renderItemHtml(item));
    }

    // III. THIẾT BỊ NỘI THẤT
    if (room.noteWoodwork && room.noteWoodwork.trim()) {
      html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;">III</td><td colspan="7" style="font-weight:700;text-align:left;white-space:nowrap;">THIẾT BỊ NỘI THẤT</td><td></td><td></td></tr>`;
      stt = 1;
      const noteLines = room.noteWoodwork.split('\n').map(l => l.trim()).filter(l => l);
      noteLines.forEach((line, li) => {
        const parsed = parseNoteDimensionLine(line);
        if (parsed.dai || parsed.rong || parsed.cao) {
          html += `<tr class="pv-item">
            <td class="pv-stt">${stt++}</td>
            <td style="padding-left:15px !important; text-align:left;">${parsed.label}</td>
            <td class="pv-num">${parsed.dai ? fmtMM(parsed.dai) : ''}</td>
            <td class="pv-num">${parsed.rong ? fmtMM(parsed.rong) : ''}</td>
            <td class="pv-num">${parsed.cao ? fmtMM(parsed.cao) : ''}</td>
            <td class="pv-center">${parsed.unit}</td>
            <td class="pv-num">${fmt(parsed.qty)}</td>
            <td class="pv-num"></td>
            <td class="pv-num"></td>
            <td class="pv-note"></td>
          </tr>`;
        } else {
          html += `<tr class="pv-item">
            <td class="pv-stt">${stt++}</td>
            <td colspan="4" style="padding-left:15px !important; text-align:left;">${parsed.label}</td>
            <td class="pv-center">${parsed.unit}</td>
            <td class="pv-num">${fmt(parsed.qty)}</td>
            <td class="pv-num"></td>
            <td class="pv-num"></td>
            <td class="pv-note"></td>
          </tr>`;
        }
      });
    }

    // IV. NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM
    const toiletText = [room.notePlumbing, room.noteWaterproof].filter(Boolean).join('\n');
    if (toiletText.trim()) {
      html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;">IV</td><td colspan="7" style="font-weight:700;text-align:left;white-space:nowrap;">NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM</td><td></td><td></td></tr>`;
      stt = 1;
      const noteLines = toiletText.split('\n').map(l => l.trim()).filter(l => l);
      noteLines.forEach((line, li) => {
        const parsed = parseNoteDimensionLine(line);
        if (parsed.dai || parsed.rong || parsed.cao) {
          html += `<tr class="pv-item">
            <td class="pv-stt">${stt++}</td>
            <td style="padding-left:15px !important; text-align:left;">${parsed.label}</td>
            <td class="pv-num">${parsed.dai ? fmtMM(parsed.dai) : ''}</td>
            <td class="pv-num">${parsed.rong ? fmtMM(parsed.rong) : ''}</td>
            <td class="pv-num">${parsed.cao ? fmtMM(parsed.cao) : ''}</td>
            <td class="pv-center">${parsed.unit}</td>
            <td class="pv-num">${fmt(parsed.qty)}</td>
            <td class="pv-num"></td>
            <td class="pv-num"></td>
            <td class="pv-note"></td>
          </tr>`;
        } else {
          html += `<tr class="pv-item">
            <td class="pv-stt">${stt++}</td>
            <td colspan="4" style="padding-left:15px !important; text-align:left;">${parsed.label}</td>
            <td class="pv-center">${parsed.unit}</td>
            <td class="pv-num">${fmt(parsed.qty)}</td>
            <td class="pv-num"></td>
            <td class="pv-num"></td>
            <td class="pv-note"></td>
          </tr>`;
        }
      });
    }

    if (roomTotal > 0) {

      html += `<tr class="pv-subtotal">

        <td colspan="8" style="text-align:right;padding-right:10px;">Cộng ${room.name}:</td>

        <td class="pv-num">${fmt(roomTotal, 0)}</td>

        <td></td>

      </tr>`;

    }

    const hasAnyPhotos = getRoomPhotosCount(room) > 0;
    if (hasAnyPhotos) {
      let photosHtml = '';
      const catNames = { overview: 'Toàn cảnh', den: 'Đèn', tudien: 'Tủ điện', maylanh: 'Máy lạnh' };
      ['overview', 'den', 'tudien', 'maylanh'].forEach(cat => {
        const catPhotos = getRoomPhotos(room, cat);
        if (catPhotos.length > 0) {
          photosHtml += `<div style="margin-top:6px; font-weight:bold; font-size:11px; color:var(--text-secondary);">📷 ${catNames[cat]}:</div>`;
          photosHtml += `<div class="pv-room-photos-gallery" style="display:flex; flex-wrap:wrap; gap:8px; margin-top:4px;">` +
            catPhotos.map(p => `
              <div class="pv-photo-thumb" style="display:inline-block; border:1px solid rgba(255,255,255,0.1); padding:2px; border-radius:6px; background:rgba(0,0,0,0.2); cursor:pointer;" onclick="window.viewPhotoData('${p.data.replace(/'/g, "\\'")}')">
                <img src="${p.data}" style="max-height:80px; display:block; border-radius:4px;" alt="${p.name}">
              </div>
            `).join('') + `</div>`;
        }
      });
      
      html += `
        <tr class="pv-room-photos-row" style="border:none !important;">
          <td style="border:none !important;"></td>
          <td colspan="9" style="border:none !important; text-align:left; padding:8px 0;">
            <div style="font-weight:bold; font-size:11px; margin-bottom:4px; color:var(--text-secondary);">📸 ẢNH HIỆN TRẠNG PHÒNG:</div>
            ${photosHtml}
          </td>
        </tr>
      `;
    }

  });

  // Chi phí khác (chỉ khi xem tất cả phòng — dùng tham số showOtherCosts)

  if (showOtherCosts) {

    const totalFloor = allRooms.reduce((s, r) => s + (+r.D||0)/1000 * (+r.R||0)/1000, 0);

    const OC_TEMPLATE = [

      { key:'transport',   label:'Phí vận chuyển',   unit:'gói', autoQty:false, defaultQty:1 },

      { key:'debris',      label:'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác', unit:'m²', autoQty:true },

      { key:'scaffold',    label:'Phí thuê giàn giáo', unit:'m²',  autoQty:true },

      { key:'design',      label:'Phí thiết kế',      unit:'m²',   autoQty:true },

      { key:'supervision', label:'Phí giám sát ngoại tỉnh', unit:'lần', autoQty:false, defaultQty:1 },

    ];

    const oc = project.otherCosts || {};

    let hasOc = false, ocStt2 = 1;

    OC_TEMPLATE.forEach(tmpl => {

      const saved = oc[tmpl.key] || {};

      const qty = tmpl.autoQty ? totalFloor : (saved.qty != null ? saved.qty : tmpl.defaultQty);

      const price = saved.price || 0;

      const total = qty * price;

      if (price > 0 || qty > 0) {

        if (!hasOc) { html += `<tr class="pv-room-hdr"><td class="pv-stt" style="text-align:center;font-weight:700;"></td><td colspan="7" style="font-weight:700;text-align:left;white-space:nowrap;">CHI PHÍ KHÁC</td><td></td><td></td></tr>`; hasOc = true; }

        grandTotal += total;

        html += `<tr class="pv-item">

          <td class="pv-stt">${ocStt2++}</td>

          <td>${tmpl.label}</td>

          <td class="pv-num"></td><td class="pv-num"></td><td class="pv-num"></td>

          <td class="pv-center">${tmpl.unit}</td>

          <td class="pv-num">${fmt(qty)}</td>

          <td class="pv-num">${price ? fmt(price, 0) : ''}</td>

          <td class="pv-num">${total ? fmt(total, 0) : ''}</td>

          <td class="pv-note">${saved.note || ''}</td>

        </tr>`;

      }

    });

  }

  document.getElementById('pv-tbody').innerHTML = html;

  document.getElementById('pv-grand-total-label').textContent = 'TỔNG CỘNG';

  document.getElementById('pv-grand-total-value').textContent =

    grandTotal > 0 ? fmt(grandTotal, 0) + ' đ' : '(Chưa nhập đơn giá)';

}

// =============================================

// 16. KHỞI TẠO

// =============================================

function init() {

  // --- Buttons dự án ---

  document.getElementById('btn-new-project')?.addEventListener('click', () => openProjectModal());

  document.getElementById('btn-new-project-empty')?.addEventListener('click', () => openProjectModal());

  document.getElementById('btn-create-project-main')?.addEventListener('click', () => openProjectModal());

  document.getElementById('btn-close-project-modal')?.addEventListener('click', closeProjectModal);

  document.getElementById('btn-cancel-project')?.addEventListener('click', closeProjectModal);

  document.getElementById('btn-save-project')?.addEventListener('click', saveProject);

  document.getElementById('btn-edit-project')?.addEventListener('click', () => openProjectModal(DB.get(state.currentProjectId)));

  document.getElementById('btn-delete-project')?.addEventListener('click', deleteCurrentProject);

  document.getElementById('btn-save-sender-default')?.addEventListener('click', () => {
    const sender = document.getElementById('proj-sender').value.trim();
    const company = document.getElementById('proj-company').value.trim();
    const companyAddr = document.getElementById('proj-company-addr').value.trim();
    try {
      localStorage.setItem('bluedecor_default_sender_info', JSON.stringify({ sender, company, companyAddr }));
      alert('✅ Đã lưu thông tin bên lập làm mặc định!');
    } catch (e) {
      alert('❌ Lỗi: Bộ nhớ đầy, không thể lưu mặc định!');
    }
  });

  // --- Event listeners cho các trường mới của Dự án ---

  const projTypeSelect = document.getElementById('proj-type');

  const projStarsSelect = document.getElementById('proj-stars');

  const projStarsGroup = document.getElementById('proj-stars-group');

  const projStarsWarning = document.getElementById('proj-stars-warning');

  projTypeSelect?.addEventListener('change', () => {

    const val = projTypeSelect.value;

    if (val === 'hotel' || val === 'resort') {

      if (projStarsGroup) projStarsGroup.style.display = 'block';

      if (projStarsSelect.value === '4-5') {

        if (projStarsWarning) projStarsWarning.style.display = 'block';

      } else {

        if (projStarsWarning) projStarsWarning.style.display = 'none';

      }

    } else {

      if (projStarsGroup) projStarsGroup.style.display = 'none';

      if (projStarsWarning) projStarsWarning.style.display = 'none';

    }

  });

  projStarsSelect?.addEventListener('change', () => {

    if (projStarsSelect.value === '4-5' && (projTypeSelect.value === 'hotel' || projTypeSelect.value === 'resort')) {

      if (projStarsWarning) projStarsWarning.style.display = 'block';

    } else {

      if (projStarsWarning) projStarsWarning.style.display = 'none';

    }

  });

  // --- Buttons phòng ---

  document.getElementById('btn-add-room')?.addEventListener('click', () => openRoomModal());

  document.getElementById('btn-close-room-modal')?.addEventListener('click', closeRoomModal);

  document.getElementById('btn-cancel-room')?.addEventListener('click', closeRoomModal);

  document.getElementById('btn-save-room')?.addEventListener('click', saveRoom);

  document.getElementById('room-function')?.addEventListener('change', (e) => {

    updateRoomDiagnostic(e.target.value);

  });

  // --- Quick buttons tên phòng (sử dụng Event Delegation cho nút sinh động) ---

  const roomQuickBtns = document.getElementById('room-quick-btns');

  if (roomQuickBtns) {

    roomQuickBtns.addEventListener('click', (e) => {

      const btn = e.target.closest('.quick-btn');

      if (btn) {

        const name = btn.dataset.name;

        document.getElementById('room-name').value = name;

        document.getElementById('room-name').focus();

        // Tự động nhận diện chức năng và chẩn đoán rủi ro hiện trường

        const autoFunc = autoDetectRoomFunction(name);

        document.getElementById('room-function').value = autoFunc;

        updateRoomDiagnostic(autoFunc);

      }

    });

  }

  // --- Tự động chẩn đoán khi người dùng gõ tên phòng trực tiếp ---

  document.getElementById('room-name')?.addEventListener('input', (e) => {

    const val = e.target.value;

    const autoFunc = autoDetectRoomFunction(val);

    document.getElementById('room-function').value = autoFunc;

    updateRoomDiagnostic(autoFunc);

  });

  // --- Live preview khi nhập kích thước ---

  ['room-D','room-R','room-H','room-doors','room-door-w','room-door-h','room-windows','room-window-w','room-window-h']

    .forEach(id => document.getElementById(id)?.addEventListener('input', () => { updatePreview(); updateZ2HDisplay(); }));

  // --- Zone toggle ---

  document.getElementById('wall-zone-toggle')?.addEventListener('change', function() {

    state.wallZoneMode = this.checked;

    document.getElementById('wall-single-mode').style.display = this.checked ? 'none' : '';

    document.getElementById('wall-zone-mode').style.display   = this.checked ? '' : 'none';

    updatePreview();

  });

  document.getElementById('wall-z1-h')?.addEventListener('input', () => { updateZ2HDisplay(); updatePreview(); });

  // --- Export Excel ---
  document.getElementById('btn-export-excel')?.addEventListener('click', exportExcel);
  document.getElementById('btn-export-excel-2')?.addEventListener('click', exportExcel);
  document.getElementById('btn-export-photos')?.addEventListener('click', exportPhotosExcel);

  // --- Preview ---

  document.getElementById('btn-preview-excel')?.addEventListener('click', openPreview);

  document.getElementById('btn-preview-excel-2')?.addEventListener('click', openPreview);

  document.getElementById('btn-close-preview')?.addEventListener('click', () =>

    document.getElementById('modal-preview').classList.remove('open'));

  document.getElementById('btn-export-from-preview')?.addEventListener('click', () => {

    document.getElementById('modal-preview').classList.remove('open');

    exportExcel();

  });

  document.getElementById('modal-preview')?.addEventListener('click', e => {

    if (e.target === e.currentTarget) e.currentTarget.classList.remove('open');

  });

  // --- Workspace tabs ---

  document.querySelectorAll('.ws-tab').forEach(tab => {

    tab.addEventListener('click', () => {

      document.querySelectorAll('.ws-tab').forEach(t => t.classList.remove('active'));

      document.querySelectorAll('.ws-panel').forEach(p => p.classList.remove('active'));

      tab.classList.add('active');

      document.getElementById(`ws-panel-${tab.dataset.wsTab}`).classList.add('active');

    });

  });

  // --- Đóng modal khi click nền ---

  ['modal-project', 'modal-room'].forEach(id => {

    document.getElementById(id)?.addEventListener('click', e => {

      if (e.target === e.currentTarget) {

        if (id === 'modal-room') {

          closeRoomModal();

        } else {

          e.currentTarget.classList.remove('open');

        }

      }

    });

  });

  // --- Phím tắt ---

  document.addEventListener('keydown', e => {

    if (e.key === 'Escape') {

      closeProjectModal();

      closeRoomModal();

    }

    if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {

      const roomModal = document.getElementById('modal-room');

      const projModal = document.getElementById('modal-project');

      if (roomModal.classList.contains('open'))  saveRoom();

      if (projModal.classList.contains('open'))  saveProject();

    }

  });

  // --- Cảnh báo khi reload trang (F5) nếu có thay đổi chưa lưu ---

  window.addEventListener('beforeunload', e => {

    const hasUnsavedRoom = isRoomFormDirty();

    const hasUnsavedInline = !!document.querySelector('tr.ci-edit-row');

    if (hasUnsavedRoom || hasUnsavedInline) {

      e.preventDefault();

      e.returnValue = '';

    }

  });

  // --- BOTTOM SHEET EVENT HANDLERS ---
  const sheet = document.getElementById('export-bottom-sheet');
  const backdrop = document.getElementById('export-sheet-backdrop');
  const btnCloseSheet = document.getElementById('btn-close-export-sheet');

  const openExportBottomSheet = () => {
    if (sheet) sheet.classList.add('active');
  };

  const closeExportBottomSheet = () => {
    if (sheet) sheet.classList.remove('active');
  };

  backdrop?.addEventListener('click', closeExportBottomSheet);
  btnCloseSheet?.addEventListener('click', closeExportBottomSheet);

  document.getElementById('btn-opt-export-excel')?.addEventListener('click', () => {
    closeExportBottomSheet();
    exportExcel();
  });

  document.getElementById('btn-opt-export-photos')?.addEventListener('click', () => {
    const currentProj = DB.get(state.currentProjectId);
    if (!currentProj) {
      alert('Vui lòng chọn dự án trước');
      return;
    }
    
    // Đếm tổng số ảnh trong tất cả các phòng
    let totalPhotos = 0;
    const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
    (currentProj.rooms || []).forEach(room => {
      if (room.photos) {
        categories.forEach(cat => {
          totalPhotos += (room.photos[cat] || []).length;
        });
      }
    });

    if (totalPhotos === 0) {
      alert('Dự án chưa có hình ảnh');
      return;
    }

    closeExportBottomSheet();
    exportPhotosExcel();
  });

  // --- BOTTOM NAVIGATION WIREUP ---
  document.querySelectorAll('.bottom-nav .nav-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      const targetTab = tab.dataset.tab;

      if (targetTab === 'export') {
        const currentProj = DB.get(state.currentProjectId);
        if (!currentProj) {
          alert('Vui lòng chọn dự án trước');
          return;
        }
        openExportBottomSheet();
        return;
      }

      document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');

      if (targetTab === 'projects') {
        document.getElementById('view-workspace')?.classList.remove('active');
        document.getElementById('view-projects')?.classList.add('active');
      } else {
        const currentProj = DB.get(state.currentProjectId);
        if (!currentProj) {
          alert('Vui lòng chọn hoặc tạo dự án mới trước.');
          document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
          document.querySelector('.bottom-nav .nav-tab[data-tab="projects"]')?.classList.add('active');
          return;
        }

        document.getElementById('view-projects')?.classList.remove('active');
        document.getElementById('view-workspace')?.classList.add('active');

        let wsTabName = 'rooms';
        if (targetTab === 'materials') wsTabName = 'vattu';

        const wsTabEl = document.querySelector(`.ws-tab[data-ws-tab="${wsTabName}"]`);
        if (wsTabEl) {
          wsTabEl.click();
        }
      }
    });
  });

  // --- HEADER BRAND BACK CLICK ---
  document.querySelector('.header-brand')?.addEventListener('click', () => {
    document.getElementById('view-workspace')?.classList.remove('active');
    document.getElementById('view-projects')?.classList.add('active');
    document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
    document.querySelector('.bottom-nav .nav-tab[data-tab="projects"]')?.classList.add('active');
  });
  const logoImg = document.querySelector('.header-brand img');
  if (logoImg) logoImg.style.cursor = 'pointer';

  // --- DASHBOARD SEARCH WIREUP ---
  document.getElementById('project-search-input')?.addEventListener('input', () => {
    renderDashboardProjects();
  });

  // --- DASHBOARD FILTER TABS WIREUP ---
  document.querySelectorAll('#project-filter-tabs .filter-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      document.querySelectorAll('#project-filter-tabs .filter-tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      renderDashboardProjects();
    });
  });

  // --- DASHBOARD SORT DROPDOWN WIREUP ---
  const btnSort = document.getElementById('btn-project-sort');
  const sortDropdown = document.getElementById('project-sort-dropdown');
  const sortText = document.getElementById('sort-text');

  if (btnSort && sortDropdown) {
    btnSort.addEventListener('click', (e) => {
      e.stopPropagation();
      sortDropdown.classList.toggle('open');
    });

    document.addEventListener('click', () => {
      sortDropdown.classList.remove('open');
    });

    sortDropdown.querySelectorAll('.sort-option').forEach(opt => {
      opt.addEventListener('click', (e) => {
        e.stopPropagation();
        sortDropdown.querySelectorAll('.sort-option').forEach(o => o.classList.remove('active'));
        opt.classList.add('active');
        
        const mode = opt.dataset.sort;
        window._dashboardSort = mode;
        
        if (sortText) {
          sortText.textContent = opt.querySelector('span').textContent;
        }
        
        sortDropdown.classList.remove('open');
        renderDashboardProjects();
      });
    });
  }

  // --- INITIALIZE DASHBOARD RENDER ---
  renderDashboardProjects();

  // --- Render ban đầu ---

  renderProjectList();

  // --- Tự mở dự án cuối cùng ---

  const projects = DB.all();

  if (projects.length > 0) {

    openProject(projects[projects.length - 1].id);

  } else {
    // Nếu chưa có dự án, hiển thị dashboard
    document.getElementById('view-workspace')?.classList.remove('active');
    document.getElementById('view-projects')?.classList.add('active');
    document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
    document.querySelector('.bottom-nav .nav-tab[data-tab="projects"]')?.classList.add('active');
  }

}

