// Nén ảnh về tối đa 1200px, JPEG 0.75 chất lượng

async function compressImage(file, maxW = 1280, quality = 0.7) {
  let finalFile = file;
  const isHeic = await isBlobHEIC(file);
  if (isHeic && typeof heic2any === 'function') {
    try {
      const converted = await heic2any({ blob: file, toType: 'image/jpeg', quality: 0.7 });
      const finalBlob = Array.isArray(converted) ? converted[0] : converted;
      const newName = file.name.replace(/\.[^.]+$/i, '.jpg');
      finalFile = new File([finalBlob], newName, { type: 'image/jpeg' });
    } catch (heicErr) {
      console.warn('heic2any failed, falling back:', heicErr);
    }
  }

  return new Promise((resolve, reject) => {
    const objectUrl = URL.createObjectURL(finalFile);
    const img = new Image();

    img.onerror = () => {
      URL.revokeObjectURL(objectUrl);
      const reader = new FileReader();
      reader.onerror = () => reject(new Error('Cannot read: ' + file.name));
      reader.onload = e => {
        const raw = e.target.result;
        const base64 = raw.split(',')[1];
        if (!base64) { reject(new Error('No base64 data')); return; }
        resolve({ name: file.name, data: 'data:image/jpeg;base64,' + base64 });
      };
      reader.readAsDataURL(file);
    };

    img.onload = () => {
      URL.revokeObjectURL(objectUrl);
      try {
        let w = img.width, h = img.height;
        if (w > maxW) { h = Math.round(h * maxW / w); w = maxW; }
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        let compressed = canvas.toDataURL('image/jpeg', quality);
        
        const sizeKB = (compressed.length * 0.75) / 1024;
        if (sizeKB > 200) {
          try {
            const img2 = new Image();
            img2.onload = () => {
              const c2 = document.createElement('canvas');
              const scale = Math.sqrt(200 / sizeKB);
              c2.width = Math.round(img2.width * scale);
              c2.height = Math.round(img2.height * scale);
              c2.getContext('2d').drawImage(img2, 0, 0, c2.width, c2.height);
              resolve({ name: file.name, data: c2.toDataURL('image/jpeg', 0.6) });
            };
            img2.onerror = () => {
              resolve({ name: file.name, data: compressed });
            };
            img2.src = compressed;
          } catch(e) {
            resolve({ name: file.name, data: compressed });
          }
        } else {
          resolve({ name: file.name, data: compressed });
        }
      } catch (err) {
        const reader = new FileReader();
        reader.onload = e => {
          const base64 = e.target.result.split(',')[1];
          resolve({ name: file.name, data: base64 ? 'data:image/jpeg;base64,' + base64 : e.target.result });
        };
        reader.onerror = () => reject(err);
        reader.readAsDataURL(file);
      }
    };

    img.src = objectUrl;
  });
}

function fileIcon(name) {

  const ext = name.split('.').pop().toLowerCase();

  const map = {

    pdf: '📄', dwg: '📐', dxf: '📐', skp: '🏠',

    '3ds': '🧊', fbx: '🧊', obj: '🧊',

    png: '🖼️', jpg: '🖼️', jpeg: '🖼️',

    zip: '🗜️', rar: '🗜️',

  };

  return map[ext] || '📁';

}

function fmtBytes(b) {

  if (b < 1024) return `${b} B`;

  if (b < 1048576) return `${(b/1024).toFixed(0)} KB`;

  return `${(b/1048576).toFixed(1)} MB`;

}

const IMAGE_PLACEHOLDER = 'data:image/svg+xml;base64,';

// Render ảnh hiện trạng

async function renderSitePhotos() {
  const project = DB.get(state.currentProjectId);
  if (!project) return;

  const photos = project.sitePhotos || [];
  const grid = document.getElementById('site-photos-grid');
  const zone = document.getElementById('site-photos-dropzone');

  if (photos.length === 0) {
    grid.innerHTML = '';
    zone.classList.remove('has-files');
    return;
  }

  zone.classList.add('has-files');

  if (state.siteObjectUrls) {
    state.siteObjectUrls.forEach(url => URL.revokeObjectURL(url));
  }
  state.siteObjectUrls = [];

  grid.innerHTML = ''; 

  for (let i = 0; i < photos.length; i++) {
    const p = photos[i];
    
    const thumb = document.createElement('div');
    thumb.className = 'photo-thumb';
    thumb.onclick = () => window.openLightbox(i, 'site');

    const img = document.createElement('img');
    img.alt = p.name;
    img.setAttribute('loading', 'lazy');
    
    let imageUrl = '';
    if (p.data && (p.data.startsWith('data:') || p.data.startsWith('blob:'))) {
      imageUrl = p.data;
    } else if (p.id) {
      try {
        const blob = await PhotoDB.getPhoto(p.id);
        if (blob) {
          imageUrl = URL.createObjectURL(blob);
          state.siteObjectUrls.push(imageUrl);
          p.data = imageUrl; // Cache URL in memory
        } else {
          imageUrl = IMAGE_PLACEHOLDER;
        }
      } catch (err) {
        console.error('Failed to get site photo:', p.id, err);
        imageUrl = IMAGE_PLACEHOLDER;
      }
    } else {
      imageUrl = IMAGE_PLACEHOLDER;
    }

    img.src = imageUrl;

    const overlay = document.createElement('div');
    overlay.className = 'photo-thumb-overlay';

    const delBtn = document.createElement('button');
    delBtn.className = 'photo-thumb-del';
    delBtn.textContent = '×';
    delBtn.onclick = (e) => {
      e.stopPropagation();
      deletePhoto(i, 'site');
    };

    overlay.appendChild(delBtn);

    const nameDiv = document.createElement('div');
    nameDiv.className = 'photo-thumb-name';
    nameDiv.textContent = p.name;

    thumb.appendChild(img);
    thumb.appendChild(overlay);
    thumb.appendChild(nameDiv);
    grid.appendChild(thumb);
  }
}

// Render file thiết kế

function renderDesignFiles() {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  const files = project.designFiles || [];

  const list = document.getElementById('design-files-list');

  const zone = document.getElementById('design-files-dropzone');

  if (files.length === 0) {

    list.innerHTML = '';

    zone.classList.remove('has-files');

    return;

  }

  zone.classList.add('has-files');

  list.innerHTML = files.map((f, i) => {

    const isImg = /\.(png|jpg|jpeg)$/i.test(f.name) && f.data;

    return `

    <div class="file-item">

      <div class="file-icon">${isImg ? `<img src="${f.data}" style="width:32px;height:32px;object-fit:cover;border-radius:4px;">` : fileIcon(f.name)}</div>

      <div class="file-info">

        <div class="file-name">${f.name}</div>

        <div class="file-meta">${fmtBytes(f.size || 0)} • ${f.type || 'File'}</div>

      </div>

      ${f.data ? `<button class="file-del" title="Xem" onclick="openLightbox(${i},'design')">🔍</button>` : ''}

      <button class="file-del" title="Xóa" onclick="deletePhoto(${i},'design')">🗑️</button>

    </div>`}).join('');

}

function deletePhoto(idx, type) {
  const project = DB.get(state.currentProjectId);
  if (!project) return;

  const key = type === 'site' ? 'sitePhotos' : 'designFiles';
  const arr = [...(project[key] || [])];

  if (type === 'site') {
    const deletedPhoto = arr[idx];
    if (deletedPhoto && deletedPhoto.id) {
      PhotoDB.deletePhoto(deletedPhoto.id).catch(err => console.error('Failed to delete photo from IndexedDB:', err));
    }
  }

  arr.splice(idx, 1);
  DB.update(state.currentProjectId, { [key]: arr });
  type === 'site' ? renderSitePhotos() : renderDesignFiles();
}

function openLightbox(idx, type) {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  const key = type === 'site' ? 'sitePhotos' : 'designFiles';

  const item = (project[key] || [])[idx];

  if (!item?.data) return;

  const isImg = item.type?.startsWith('image/') || /\.(png|jpg|jpeg|gif|webp)$/i.test(item.name);

  if (isImg) {

    // Hiện lightbox ảnh

    const lb = document.createElement('div');

    lb.className = 'lightbox';

    lb.innerHTML = `<span class="lightbox-close">✕</span><img src="${item.data}" alt="${item.name}">`;

    lb.addEventListener('click', () => lb.remove());

    document.body.appendChild(lb);

  } else {

    // File không phải ảnh: tạo link tải về

    const a = document.createElement('a');

    a.href = item.data;

    a.download = item.name;

    a.click();

  }

}

// Xử lý upload ảnh hiện trạng

async function handleSitePhotos(files) {
  const project = DB.get(state.currentProjectId);
  if (!project) return;

  const existing = project.sitePhotos || [];
  const newPhotos = [];
  let skipped = 0;

  for (const f of files) {
    if (!f.type.startsWith('image/')) continue;
    if (f.size > 15 * 1024 * 1024) { skipped++; continue; }
    try {
      const compressed = await compressImage(f, 1280, 0.7);
      const blob = dataURLtoBlob(compressed.data);
      if (blob) {
        const photoId = genId();
        await PhotoDB.savePhoto(photoId, blob);
        newPhotos.push({
          id: photoId,
          name: f.name,
          date: new Date().toISOString(),
          data: URL.createObjectURL(blob)
        });
      }
    } catch (e) { console.warn('Compress failed:', f.name, e); }
  }

  if (skipped > 0) alert(`${skipped} ảnh bị bỏ qua (quá 15MB hoặc không phải ảnh)`);

  DB.update(state.currentProjectId, { sitePhotos: [...existing, ...newPhotos] });
  renderSitePhotos();
}

// Xử lý upload file thiết kế

async function handleDesignFiles(files) {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  const existing = project.designFiles || [];

  const newFiles = [];

  for (const f of files) {

    const isImg = f.type.startsWith('image/');

    if (isImg && f.size < 10 * 1024 * 1024) {

      // Ảnh: nén trước khi lưu

      const compressed = await compressImage(f, 1600);

      newFiles.push({ name: f.name, size: f.size, type: f.type, data: compressed.data });

    } else if (!isImg && f.size < 5 * 1024 * 1024) {

      // File nhỏ (< 5MB, PDF/DWG...): lưu base64 để xem/tải lại

      const data = await new Promise(resolve => {

        const reader = new FileReader();

        reader.onload = e => resolve(e.target.result);

        reader.readAsDataURL(f);

      });

      newFiles.push({ name: f.name, size: f.size, type: f.type, data });

    } else {

      // File quá lớn (> 5MB): chỉ lưu metadata, không thể xem lại

      newFiles.push({ name: f.name, size: f.size, type: f.type, note: 'File > 5MB — không lưu được nội dung' });

    }

  }

  DB.update(state.currentProjectId, { designFiles: [...existing, ...newFiles] });

  renderDesignFiles();

}

// Gọi render khi chuyển sang tab media

function renderMediaPanel() {

  renderSitePhotos();

  renderDesignFiles();

}

// Init media listeners (gọi từ init)

function initMediaListeners() {

  // Upload ảnh hiện trạng

  const siteInput = document.getElementById('upload-site-photos');

  siteInput.addEventListener('change', e => { handleSitePhotos([...e.target.files]); siteInput.value=''; });

  // Upload file thiết kế

  const designInput = document.getElementById('upload-design-files');

  designInput.addEventListener('change', e => { handleDesignFiles([...e.target.files]); designInput.value=''; });

  // Drag & drop — site photos

  const siteZone = document.getElementById('site-photos-dropzone');

  siteZone.addEventListener('dragover', e => { e.preventDefault(); siteZone.classList.add('drag-over'); });

  siteZone.addEventListener('dragleave', () => siteZone.classList.remove('drag-over'));

  siteZone.addEventListener('drop', e => {

    e.preventDefault();

    siteZone.classList.remove('drag-over');

    handleSitePhotos([...e.dataTransfer.files]);

  });

  // Drag & drop — design files

  const designZone = document.getElementById('design-files-dropzone');

  designZone.addEventListener('dragover', e => { e.preventDefault(); designZone.classList.add('drag-over'); });

  designZone.addEventListener('dragleave', () => designZone.classList.remove('drag-over'));

  designZone.addEventListener('drop', e => {

    e.preventDefault();

    designZone.classList.remove('drag-over');

    handleDesignFiles([...e.dataTransfer.files]);

  });

  // Render khi bấm tab Tài Liệu

  document.querySelector('[data-ws-tab="media"]')?.addEventListener('click', renderMediaPanel);

}

