const VatTuDB = {
  KEY: 'bluedecor_vattu_v1',
  get()    { try { return JSON.parse(localStorage.getItem(this.KEY) || '[]'); } catch { return []; } },
  set(arr) {
    try {
      localStorage.setItem(this.KEY, JSON.stringify(arr));
    } catch (e) {
      if (e.name === 'QuotaExceededError') {
        showToast('Bộ nhớ trình duyệt đã đầy! Không thể lưu thư viện vật tư.', 'error');
      } else {
        console.error('VatTuDB save error:', e);
      }
    }
  },
  clear()  { localStorage.removeItem(this.KEY); },
};

// Trạng thái Vật Tư

let _vtPage = 1;

const _vtPageSize = 50;

let _vtImportData = [];   // raw rows từ Excel

let _vtColCount = 0;

let _vtHeaders = [];

// ── Nhận diện cột tự động ─────────────────────────────────

const VT_FIELD_ALIASES = {

  code:     ['mã','ma','code','id','sku','mã vật tư'],

  name:     ['tên','ten','name','hạng mục','vật tư','tên vật tư','ten vat tu','mô tả','mo ta','description','item','hàng'],

  unit:     ['đơn vị','đvt','unit','đv','dvt'],

  price:    ['đơn giá','gia','giá','price','don gia','đơn giá (vnđ)','giá bán','đg'],

  supplier: ['nhà cung cấp','ncc','supplier','nhà cc','nha cung cap','vendor'],

  category: ['danh mục','loại','category','nhóm','cat','danh muc','nhóm hàng'],

  note:     ['ghi chú','note','notes','ghi chu','remark','remarks','mô tả thêm'],

};

const VT_FIELD_LABELS = {

  code: 'Mã vật tư', name: 'Tên vật tư *', unit: 'Đơn vị',

  price: 'Đơn giá', supplier: 'Nhà cung cấp', category: 'Danh mục', note: 'Ghi chú',

};

function autoDetectVtCols(headers) {

  const result = {};

  headers.forEach((h, idx) => {

    const hLower = (h || '').toLowerCase().trim();

    for (const [field, aliases] of Object.entries(VT_FIELD_ALIASES)) {

      if (result[field] !== undefined) continue;

      if (aliases.some(a => hLower.includes(a) || a.includes(hLower))) {

        result[field] = idx;

      }

    }

  });

  return result;

}

// ── Chọn file ─────────────────────────────────────────────

function onVatTuFileSelect(event) {

  const file = event.target.files[0];

  if (!file) return;

  event.target.value = '';

  const reader = new FileReader();

  reader.onload = (e) => {

    const wb = XLSX.read(e.target.result, { type: 'array' });

    const ws = wb.Sheets[wb.SheetNames[0]];

    const rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });

    // Tìm hàng header: hàng đầu tiên có ít nhất 2 ô text

    let headerRow = 0;

    for (let i = 0; i < Math.min(10, rows.length); i++) {

      const textCells = rows[i].filter(c => typeof c === 'string' && c.trim().length > 1);

      if (textCells.length >= 2) { headerRow = i; break; }

    }

    _vtHeaders   = (rows[headerRow] || []).map(c => String(c));

    _vtImportData = rows.slice(headerRow + 1).filter(r => r.some(c => c !== '' && c != null));

    _vtColCount  = _vtHeaders.length;

    openVatTuMapModal();

  };

  reader.readAsArrayBuffer(file);

}

// ── Modal ánh xạ cột ──────────────────────────────────────

function openVatTuMapModal() {

  const autoMap = autoDetectVtCols(_vtHeaders);

  const colOptions = ['<option value="">— Bỏ qua —</option>',

    ..._vtHeaders.map((h,i) => `<option value="${i}">${String.fromCharCode(65+i) || i}: ${h}</option>`)

  ].join('');

  const fieldsHtml = Object.entries(VT_FIELD_LABELS).map(([field, label]) => {

    const selected = autoMap[field] !== undefined ? autoMap[field] : '';

    const opts = colOptions.replace(`value="${selected}"`, `value="${selected}" selected`);

    return `<div><label>${label}</label><select id="vtmap-${field}">${opts}</select></div>`;

  }).join('');

  document.getElementById('vattu-map-fields').innerHTML = fieldsHtml;

  // Preview 5 dòng

  const previewRows = _vtImportData.slice(0, 5);

  let previewHtml = '<table><thead><tr>' +

    _vtHeaders.map(h => `<th>${h}</th>`).join('') + '</tr></thead><tbody>' +

    previewRows.map(r =>

      '<tr>' + _vtHeaders.map((_,i) => `<td>${r[i] ?? ''}</td>`).join('') + '</tr>'

    ).join('') + '</tbody></table>';

  document.getElementById('vattu-preview-table').innerHTML = previewHtml;

  document.getElementById('modal-vattu-map').classList.add('active');

  if (window.lucide) lucide.createIcons();

}

// ── Xác nhận import ───────────────────────────────────────

function confirmImportVatTu() {

  const getCol = (field) => {

    const val = document.getElementById(`vtmap-${field}`)?.value;

    return val !== '' && val !== undefined ? +val : -1;

  };

  const nameCol = getCol('name');

  if (nameCol < 0) { alert('Vui lòng chọn cột "Tên vật tư"!'); return; }

  const colMap = {};

  Object.keys(VT_FIELD_LABELS).forEach(f => { colMap[f] = getCol(f); });

  const existing = VatTuDB.get();

  let added = 0, skipped = 0;

  _vtImportData.forEach((row, idx) => {

    const name = String(row[colMap.name] ?? '').trim();

    if (!name) { skipped++; return; }

    const record = {

      id:       `vt_${Date.now()}_${idx}`,

      code:     colMap.code    >= 0 ? String(row[colMap.code]     ?? '').trim() : '',

      name,

      unit:     colMap.unit    >= 0 ? String(row[colMap.unit]     ?? '').trim() : '',

      price:    colMap.price   >= 0 ? parseFloat(String(row[colMap.price] ?? '').replace(/[^0-9.]/g,'')) || 0 : 0,

      supplier: colMap.supplier>= 0 ? String(row[colMap.supplier] ?? '').trim() : '',

      category: colMap.category>= 0 ? String(row[colMap.category] ?? '').trim() : '',

      note:     colMap.note    >= 0 ? String(row[colMap.note]     ?? '').trim() : '',

    };

    existing.push(record);

    added++;

  });

  VatTuDB.set(existing);

  document.getElementById('modal-vattu-map').classList.remove('active');

  renderVatTuTable();

  refreshVatTuCategories();

  alert(`✅ Import xong: ${added} vật tư được thêm${skipped > 0 ? `, ${skipped} dòng bỏ qua (trống tên)` : ''}.`);

}

// ── Render bảng ────────────────────────────────────────────

function renderVatTuTable() {

  const search  = (document.getElementById('vattu-search')?.value || '').toLowerCase().trim();

  const catFilter = document.getElementById('vattu-filter-cat')?.value || '';

  let all = VatTuDB.get();

  // Lọc

  if (search)    all = all.filter(v => v.name.toLowerCase().includes(search) || (v.code||'').toLowerCase().includes(search) || (v.supplier||'').toLowerCase().includes(search));

  if (catFilter) all = all.filter(v => v.category === catFilter);

  const total = all.length;

  const totalPages = Math.max(1, Math.ceil(total / _vtPageSize));

  if (_vtPage > totalPages) _vtPage = 1;

  const page = all.slice((_vtPage - 1) * _vtPageSize, _vtPage * _vtPageSize);

  // Stats

  const rawAll = VatTuDB.get();

  document.getElementById('vattu-stats').textContent =

    `${rawAll.length.toLocaleString()} vật tư trong thư viện  ·  hiển thị ${total.toLocaleString()} kết quả`;

  // Empty

  document.getElementById('vattu-empty').style.display      = rawAll.length === 0 ? 'block' : 'none';

  document.getElementById('vattu-table-wrap').style.display = rawAll.length === 0 ? 'none'  : '';

  // Rows

  const tbody = document.getElementById('vattu-tbody');

  const offset = (_vtPage - 1) * _vtPageSize;

  tbody.innerHTML = page.map((v, i) => `

    <tr>

      <td style="color:var(--text-muted);font-size:11px;text-align:center;">${offset + i + 1}</td>

      <td class="td-code">${v.code || '—'}</td>

      <td style="font-weight:500;">${v.name}</td>

      <td style="text-align:center;color:var(--text-secondary);">${v.unit || ''}</td>

      <td class="td-price">${v.price ? v.price.toLocaleString('vi-VN') + ' đ' : '—'}</td>

      <td class="td-supplier">${v.supplier || '—'}</td>

      <td><span class="td-cat">${v.category || ''}</span></td>

      <td style="font-size:12px;color:var(--text-muted);">${v.note || ''}</td>

      <td>

        <div class="td-actions">

          <button onclick="deleteVatTu('${v.id}')" title="Xóa">

            <i data-lucide="trash-2" style="width:13px;height:13px;"></i>

          </button>

        </div>

      </td>

    </tr>`).join('');

  // Pagination

  const pg = document.getElementById('vattu-pagination');

  if (totalPages <= 1) { pg.innerHTML = ''; } else {

    let pgHtml = '';

    for (let p = 1; p <= totalPages; p++) {

      if (totalPages > 10 && p > 3 && p < totalPages - 2 && Math.abs(p - _vtPage) > 2) {

        if (p === 4) pgHtml += '<span style="color:var(--text-muted)">…</span>';

        continue;

      }

      pgHtml += `<button class="vattu-page-btn${p === _vtPage ? ' active' : ''}" onclick="_vtPage=${p};renderVatTuTable()">${p}</button>`;

    }

    pg.innerHTML = `<span style="font-size:12px;color:var(--text-muted);margin-right:4px;">Trang ${_vtPage}/${totalPages}</span>${pgHtml}`;

  }

  if (window.lucide) lucide.createIcons();

}

function refreshVatTuCategories() {

  const all  = VatTuDB.get();

  const cats = [...new Set(all.map(v => v.category).filter(Boolean))].sort();

  const sel  = document.getElementById('vattu-filter-cat');

  if (!sel) return;

  const cur  = sel.value;

  sel.innerHTML = '<option value="">Tất cả danh mục</option>' +

    cats.map(c => `<option value="${c}"${c === cur ? ' selected' : ''}>${c}</option>`).join('');

}

function deleteVatTu(id) {

  if (!confirm('Xóa vật tư này?')) return;

  VatTuDB.set(VatTuDB.get().filter(v => v.id !== id));

  renderVatTuTable();

  refreshVatTuCategories();

}

function clearVatTuDB() {

  const n = VatTuDB.get().length;

  if (n === 0) { alert('Thư viện đang trống.'); return; }

  if (!confirm(`Xóa toàn bộ ${n} vật tư trong thư viện?`)) return;

  VatTuDB.clear();

  renderVatTuTable();

  refreshVatTuCategories();

}

