function getRoomPhotosCount(room) {
  if (!room || !room.photos) return 0;
  if (Array.isArray(room.photos)) return room.photos.length;
  let count = 0;
  ['overview', 'den', 'tudien', 'maylanh'].forEach(cat => {
    if (Array.isArray(room.photos[cat])) {
      count += room.photos[cat].length;
    }
  });
  return count;
}

function getRoomPhotos(room, category) {
  if (!room || !room.photos) return [];
  if (Array.isArray(room.photos)) {
    return category === 'overview' ? room.photos : [];
  }
  return room.photos[category] || [];
}

window.viewPhotoData = function(data) {
  const w = window.open();
  w.document.write(`<img src="${data}" style="max-width:100%;height:auto;">`);
};

async function renderCategorizedRoomPhotos(category) {
  const thumbs = document.getElementById(`room-photo-thumbs-${category}`);
  if (!thumbs) return;
  
  if (state.categoryObjectUrls && state.categoryObjectUrls[category]) {
    state.categoryObjectUrls[category].forEach(url => URL.revokeObjectURL(url));
  }
  if (!state.categoryObjectUrls) state.categoryObjectUrls = {};
  state.categoryObjectUrls[category] = [];

  const photos = (state.roomCategorizedPhotos && state.roomCategorizedPhotos[category]) || [];
  thumbs.innerHTML = ''; 

  for (let i = 0; i < photos.length; i++) {
    const p = photos[i];
    
    const wrapper = document.createElement('div');
    wrapper.className = 'room-photo-thumb';
    wrapper.title = p.name;

    const img = document.createElement('img');
    img.alt = p.name;
    
    let imageUrl = '';
    if (p.data && (p.data.startsWith('data:') || p.data.startsWith('blob:'))) {
      imageUrl = p.data;
    } else if (p.id) {
      try {
        const blob = await PhotoDB.getPhoto(p.id);
        if (blob) {
          imageUrl = URL.createObjectURL(blob);
          state.categoryObjectUrls[category].push(imageUrl);
          p.data = imageUrl; // Cache URL in memory
        } else {
          imageUrl = IMAGE_PLACEHOLDER;
        }
      } catch (err) {
        console.error('Failed to get photo:', p.id, err);
        imageUrl = IMAGE_PLACEHOLDER;
      }
    } else {
      imageUrl = IMAGE_PLACEHOLDER;
    }

    img.src = imageUrl;
    img.onclick = () => window.viewPhotoData(imageUrl);

    const delBtn = document.createElement('span');
    delBtn.className = 'thumb-del';
    delBtn.title = 'Xóa ảnh';
    delBtn.textContent = '✕';
    delBtn.onclick = (e) => {
      e.stopPropagation();
      removeCategorizedRoomPhoto(category, i);
    };

    wrapper.appendChild(img);
    wrapper.appendChild(delBtn);
    thumbs.appendChild(wrapper);
  }
}

function removeCategorizedRoomPhoto(category, idx) {
  if (!state.roomCategorizedPhotos || !state.roomCategorizedPhotos[category]) return;
  state.roomCategorizedPhotos[category].splice(idx, 1);
  renderCategorizedRoomPhotos(category);
}

async function handleRoomPhotoSelect(files, category) {
  if (!files || files.length === 0) return;
  if (!state.roomCategorizedPhotos) {
    state.roomCategorizedPhotos = {
      overview: [], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: []
    };
  }
  if (!state.roomCategorizedPhotos[category]) {
    state.roomCategorizedPhotos[category] = [];
  }

  const promises = Array.from(files).map(async file => {
    const isImage = file.type.startsWith('image/') ||
                    file.type === '' ||
                    /\.(heic|heif|jpg|jpeg|png|webp|gif)$/i.test(file.name);
    if (!isImage) return;

    try {
      const compressed = await compressImage(file, 1280, 0.7);
      const blob = dataURLtoBlob(compressed.data);
      if (blob) {
        const photoId = genId();
        await PhotoDB.savePhoto(photoId, blob);
        state.roomCategorizedPhotos[category].push({
          id: photoId,
          name: file.name,
          date: new Date().toISOString(),
          data: URL.createObjectURL(blob)
        });
      }
    } catch (e) {
      console.warn('Compress failed:', file.name, e);
      showToast('Không thể xử lý ảnh: ' + file.name, 'error');
    }
  });

  await Promise.all(promises);
  renderCategorizedRoomPhotos(category);
  
  const inputEl = document.getElementById('room-photo-input-' + category);
  if (inputEl) {
    inputEl.value = '';
  }
}

function saveDataToStorage() {
  if (state.currentProjectId) {
    const project = DB.get(state.currentProjectId);
    if (project) {
      const projects = DB.load();
      const idx = projects.findIndex(p => p.id === project.id);
      if (idx !== -1) {
        projects[idx] = project;
      }
      DB.save(projects);
    }
  }
}

function updateUIWorkspace() {
  refreshWorkspace();
}

async function handleRoomCardPhotoSelect(event, roomId) {
  const files = event.target.files;
  if (!files || files.length === 0) return;

  const project = DB.get(state.currentProjectId);
  if (!project) return;

  const room = (project.rooms || []).find(r => r.id === roomId);
  if (!room) return;

  if (!room.photos) room.photos = { overview: [], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: [] };
  if (Array.isArray(room.photos)) {
    room.photos = { overview: [...room.photos], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: [] };
  }
  if (!room.photos.overview) {
    room.photos.overview = [];
  }

  const promises = Array.from(files).map(file => {
    if (!file.type.startsWith('image/')) return Promise.resolve();
    
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = e => {
        const img = new Image();
        img.onload = () => {
          let w = img.width;
          let h = img.height;
          const maxW = 600;
          if (w > maxW) {
            h = Math.round(h * maxW / w);
            w = maxW;
          }
          const canvas = document.createElement('canvas');
          canvas.width = w;
          canvas.height = h;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0, w, h);
          resolve({
            name: file.name,
            data: canvas.toDataURL('image/jpeg', 0.6)
          });
        };
        img.onerror = () => resolve(null);
        img.src = e.target.result;
      };
      reader.onerror = () => resolve(null);
      reader.readAsDataURL(file);
    });
  });

  const compressedResults = await Promise.all(promises);
  compressedResults.forEach(res => {
    if (res) {
      room.photos.overview.push(res);
    }
  });

  DB.updateRoom(state.currentProjectId, roomId, { photos: room.photos });
  saveDataToStorage();
  updateUIWorkspace();
}


function docDepBoNho() {
  let totalBefore = 0;
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k)) totalBefore += localStorage[k].length * 2;
  }

  const keysToKeep = ['bkl_v1_projects', 'bkl_settings', 'bkl_vattu'];
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k) && !keysToKeep.includes(k)) {
      localStorage.removeItem(k);
    }
  }

  let totalAfter = 0;
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k)) totalAfter += localStorage[k].length * 2;
  }

  const freed = ((totalBefore - totalAfter) / 1024).toFixed(0);
  showToast(`Đã giải phóng ${freed} KB bộ nhớ`, 'success');
}

function showToast(message, type = 'info', duration = 3500) {
  let container = document.getElementById('toast-container');
  if (!container) {
    container = document.createElement('div');
    container.id = 'toast-container';
    document.body.appendChild(container);
  }

  const toast = document.createElement('div');
  toast.className = `toast toast-${type}`;
  
  let iconHtml = '';
  if (type === 'success') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>`;
  } else if (type === 'warning') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>`;
  } else if (type === 'error' || type === 'danger') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>`;
  } else {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>`;
  }

  toast.innerHTML = `
    <span class="toast-icon" style="display: flex; align-items: center; justify-content: center;">${iconHtml}</span>
    <span class="toast-message" style="flex-grow: 1; margin-right: 8px;">${message}</span>
    <button class="toast-close" style="background: none; border: none; color: inherit; opacity: 0.6; cursor: pointer; padding: 4px; display: flex; align-items: center; justify-content: center;" aria-label="Đóng">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>
  `;

  const close = () => {
    toast.classList.remove('visible');
    toast.addEventListener('transitionend', () => toast.remove(), { once: true });
  };

  toast.querySelector('.toast-close').addEventListener('click', close);
  container.appendChild(toast);

  requestAnimationFrame(() => {
    toast.classList.add('visible');
  });

  if (duration > 0) {
    setTimeout(close, duration);
  }
}

